let overlayVariants = {
  "visible": {
    opacity: 1,
    display: "block",
  },
  "hidden": {
    opacity: 0,
    transitionEnd: {
      display: "none",
    },
  }
}

var parallaxInstance = null;

let parallaxTimeout = null;

export default function Component({ data, allProjects }) {
  let [all, setAll] = useState([]);
  let [prevOpen, setPrevOpen] = useState(0);
  let [overlayOpen, setOverlayOpen] = useState(false);
  let containerRef = useRef();


  useEffect(() => {
    
    setAll(data.islands)

    setTimeout(() => {
      var scene = document.getElementById('scene');
      parallaxInstance = new Parallax(scene, {
        // relativeInput: true
        // scalarX: 100,
        // scalarY: 100,
      });

    }, 0)
  }, []);


  useEffect(() => {

    let openCount = 0;

    all.forEach((item) => {

      if(item.isOpen) {
        openCount += 1;
      }

    })

    if(openCount > 0) {

      setOverlayOpen(true)

    } else {
      setOverlayOpen(false)

      clearTimeout(parallaxTimeout)

      parallaxInstance?.disable()
      
      parallaxTimeout = setTimeout(() => {
        parallaxInstance?.enable()
      }, 1000)
    }
  },[all])

  let toggleIsland = (index) => {
    setPrevOpen(index);
    let copyAll = JSON.parse(JSON.stringify(all))
    copyAll[index].isOpen = true
    setAll(copyAll)
  }

  let closeAll = () => {
    let copyAll = JSON.parse(JSON.stringify(all))

    copyAll.forEach(item => item.isOpen = false)

    setAll(copyAll)
  }


  return (
    <Container ref={containerRef} id="scene">
        {all.map((item, index) => 
        <Island data={item} dataAll={all} index={index} toggle={() => toggleIsland(index)} prevOpen={prevOpen} allProjects={allProjects} />
        )}
        <Overlay animate={overlayOpen ? "visible" : "hidden"} variants={overlayVariants} onClick={() => closeAll()}/>
    </Container>
  )
}
